import { ScaleTime } from 'd3-scale';
import { isUndefined } from 'lodash-es';
import type { PointerEvent } from 'react';

import { useGridPlotSize } from '../../chart-grid/hooks/useGridPlotSize.js';
import { SelectionBackdrop } from '../../selection-area/SelectionBackdrop.js';
import { useSynchronizedSelection } from '../hooks/useSynchronizedSelection.js';
import { containerSVG } from '../SharedChartInteractions.sty.js';

type SynchronizedSelectionAreaProps = {
  scale: ScaleTime<number, number>;
};

export const SynchronizedSelectionArea = ({
  scale,
}: SynchronizedSelectionAreaProps) => {
  const synchronizedSelectionArea = useSynchronizedSelection();
  const { height } = useGridPlotSize();

  const { startX, endX, resetSelectionState } = synchronizedSelectionArea;

  if (!synchronizedSelectionArea || isUndefined(startX) || isUndefined(endX)) {
    return null;
  }

  const scaledStartX = scale(startX);
  const scaledDndX = scale(endX);

  const handleOnPointerDown = (event: PointerEvent<SVGSVGElement>) => {
    event.preventDefault();
    resetSelectionState?.();
  };

  return (
    <svg className={containerSVG} onPointerDown={handleOnPointerDown}>
      <SelectionBackdrop
        focusable={false}
        interactable={false}
        startX={scaledStartX}
        endX={scaledDndX}
        height={height}
        isSynchronizedSelection={true}
      />
    </svg>
  );
};

SynchronizedSelectionArea['displayName'] = 'SynchronizedSelectionArea';
